def ones_complement(bits):
    return "".join("1" if b == "0" else "0" for b in bits)

def twos_complement(bits):
    ones = ones_complement(bits)
    carry = 1
    result = list(ones)
    for i in range(len(result) - 1, -1, -1):
        total = int(result[i]) + carry
        result[i] = str(total % 2)
        carry = total // 2
        if carry == 0:
            break
    return "".join(result)

n = "10110"
print(f"2진수: {n}")
print(f"1의 보수: {ones_complement(n)}")
print(f"2의 보수: {twos_complement(n)}")

def ones_complement(bits):
    return "".join("1" if b == "0" else "0" for b in bits)

def add_bits(a, b):
    carry = 0
    result = [""] * len(a)
    for i in range(len(a) - 1, -1, -1):
        total = int(a[i]) + int(b[i]) + carry
        result[i] = str(total % 2)
        carry = total // 2
    return "".join(result), carry

def twos_complement(bits):
    comp, _ = add_bits(ones_complement(bits), "0001")
    return comp

def subtract_by_twos_complement(a, b):
    comp = twos_complement(b)          # 1) 감수의 2의 보수
    result, carry = add_bits(a, comp)  # 2) 피감수 + 2의 보수
    if carry:                          # 3) 자리 올림수는 버린다
        return result
    return "-" + twos_complement(result)

a, b = "1011", "1010"
print(f"{a} - {b} 를 2의 보수로 계산")
print("감수의 2의 보수:", twos_complement(b))
print("결과:", subtract_by_twos_complement(a, b))

def open_cards(binary):
    n = len(binary)
    values, total = [], 0
    for i, bit in enumerate(binary):
        if bit == "1":
            v = 2 ** (n - 1 - i)  # 펼친 카드의 자리값
            values.append(v)
            total += v
    return values, total

for b in ["000001011", "000010101", "001100011"]:
    values, total = open_cards(b)
    joined = " + ".join(str(v) for v in values)
    print(f"{b} -> {joined} = {total}")
